+            "EXPLAIN SELECT * FROM commands",
+            "WITH cte AS (SELECT 1) SELECT * FROM cte",
+        ];
+
+        for query in &invalid_queries {
+            let trimmed = query.trim().to_uppercase();
+            assert!(
